     7→
     8→	"github.com/grafana/grafana-plugin-sdk-go/backend"
     9→	"github.com/grafana/grafana-plugin-sdk-go/backend/datasource"
    10→	sdkhttpclient "github.com/grafana/grafana-plugin-sdk-go/backend/httpclient"
    11→	"github.com/grafana/grafana-plugin-sdk-go/backend/instancemgmt"
    12→	"github.com/grafana/grafana-plugin-sdk-go/backend/log"
    13→
    14→	"github.com/grafana/grafana/pkg/promlib/client"
    15→	"github.com/grafana/grafana/pkg/promlib/instrumentation"
    16→	"github.com/grafana/grafana/pkg/promlib/querydata"
    17→	"github.com/grafana/grafana/pkg/promlib/resource"
    18→)
    19→
    20→type Service struct {
    21→	im     instancemgmt.InstanceManager
    22→	logger log.Logger
    23→}
    24→
    25→type instance struct {
    26→	queryData *querydata.QueryData
    27→	resource  *resource.Resource
    28→}
    29→
    30→type ExtendOptions func(ctx context.Context, settings backend.DataSourceInstanceSettings, clientOpts *sdkhttpclient.Options, log log.Logger) error
    31→
    32→func NewService(httpClientProvider *sdkhttpclient.Provider, plog log.Logger, extendOptions ExtendOptions) *Service {
    33→	if httpClientProvider == nil {
    34→		httpClientProvider = sdkhttpclient.NewProvider()
    35→	}
    36→	return &Service{
    37→		im:     datasource.NewInstanceManager(newInstanceSettings(httpClientProvider, plog, extendOptions)),
    38→		logger: plog,
    39→	}
    40→}
    41→
    42→// Dispose here tells plugin SDK that plugin wants to clean up resources when a new instance
    43→// created. As soon as datasource settings change detected by SDK old datasource instance will
    44→// be disposed and a new one will be created using NewSampleDatasource factory function.
    45→func (s *Service) Dispose() {
    46→	// Clean up datasource instance resources.
    47→	s.logger.Debug("Disposing the instance...")
    48→}
    49→
    50→func newInstanceSettings(httpClientProvider *sdkhttpclient.Provider, log log.Logger, extendOptions ExtendOptions) datasource.InstanceFactoryFunc {
    51→	return func(ctx context.Context, settings backend.DataSourceInstanceSettings) (instancemgmt.Instance, error) {
    52→		// Creates a http roundTripper.
    53→		opts, err := client.CreateTransportOptions(ctx, settings, log)
    54→		if err != nil {
    55→			return nil, fmt.Errorf("error creating transport options: %v", err)
    56→		}
    57→
    58→		if extendOptions != nil {
    59→			err = extendOptions(ctx, settings, opts, log)
    60→			if err != nil {
    61→				return nil, fmt.Errorf("error extending transport options: %v", err)
    62→			}
    63→		}
    64→
    65→		httpClient, err := httpClientProvider.New(*opts)
    66→		if err != nil {
    67→			return nil, fmt.Errorf("error creating http client: %v", err)
    68→		}
    69→
    70→		featureToggles := backend.GrafanaConfigFromContext(ctx).FeatureToggles()
    71→
    72→		// New version using custom client and better response parsing
    73→		qd, err := querydata.New(httpClient, settings, log, featureToggles)
    74→		if err != nil {
    75→			return nil, err
    76→		}
    77→
    78→		// Resource call management using new custom client same as querydata
    79→		r, err := resource.New(httpClient, settings, log)
    80→		if err != nil {
    81→			return nil, err
    82→		}
    83→
    84→		return instance{
    85→			queryData: qd,
    86→			resource:  r,
    87→		}, nil
    88→	}
    89→}
    90→
    91→func (s *Service) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
    92→	if len(req.Queries) == 0 {
    93→		err := fmt.Errorf("query contains no queries")
    94→		instrumentation.UpdateQueryDataMetrics(err, nil)
    95→		return &backend.QueryDataResponse{}, err
    96→	}
    97→
    98→	i, err := s.getInstance(ctx, req.PluginContext)
    99→	if err != nil {
   100→		instrumentation.UpdateQueryDataMetrics(err, nil)
   101→		return nil, err
   102→	}
   103→
   104→	qd, err := i.queryData.Execute(ctx, req)
   105→	instrumentation.UpdateQueryDataMetrics(err, qd)
   106→
   107→	return qd, err
   108→}
   109→
   110→func (s *Service) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
   111→	i, err := s.getInstance(ctx, req.PluginContext)
   112→	if err != nil {
   113→		return err
   114→	}
   115→
   116→	switch {
   117→	case strings.EqualFold(req.Path, "suggestions"):
   118→		resp, err := i.resource.GetSuggestions(ctx, req)
   119→		if err != nil {
   120→			return err
   121→		}
   122→		return sender.Send(resp)
   123→	}
   124→
   125→	resp, err := i.resource.Execute(ctx, req)
   126→	if err != nil {
   127→		return err
   128→	}
   129→
   130→	return sender.Send(resp)
   131→}
   132→
   133→func (s *Service) getInstance(ctx context.Context, pluginCtx backend.PluginContext) (*instance, error) {
   134→	i, err := s.im.Get(ctx, pluginCtx)
   135→	if err != nil {
   136→		return nil, err
   137→	}
   138→	in := i.(instance)
   139→	return &in, nil
   140→}
